parameters.functionCode:
// PII scrubbing pre-LLM (defesa em profundidade)
const input = $input.first().json;
const raw = (input.body && input.body.message && input.body.message.text) || '';
const sender = (input.body && input.body.sender) || 'unknown';

// Regex simples para CPF/RG/telefone/email
const patterns = {
  cpf: /\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/g,
  rg: /\b\d{1,2}\.?\d{3}\.?\d{3}-?\d{1}\b/g,
  phone: /\b\(\d{2}\)\s?9?\d{4}-?\d{4}\b/g,
  email: /\b[\w.-]+@[\w.-]+\.\w+\b/g
};

let scrubbed = raw;
let findings = [];
let redactionCount = 0;

for (const [type, pattern] of Object.entries(patterns)) {
  const matches = scrubbed.match(pattern);
  if (matches) {
    findings.push({ type, count: matches.length });
    redactionCount += matches.length;
    scrubbed = scrubbed.replace(pattern, `[${type.toUpperCase()}_REDACTED]`);
  }
}

return { json: { sender, raw, scrubbed, findings, redactionCount } };

